// src/components/Layouts/StaffLayout.jsx
import React from 'react';
import { Outlet, Navigate, Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import './StaffLayout.css'; // Nếu bạn có file css riêng, hoặc dùng inline style

const StaffLayout = () => {
  const { currentUser, loading, logout } = useAuth();

  // 1. Màn hình chờ khi đang check login
  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <h2>Đang tải dữ liệu...</h2>
      </div>
    );
  }

  // 2. Nếu chưa login, đá về trang login
  if (!currentUser) {
    return <Navigate to="/login" replace />;
  }

  // 3. (Tuỳ chọn) Kiểm tra quyền Staff. 
  // Nếu logic của bạn cho phép cả admin vào thì sửa điều kiện này.
  // Lưu ý: đảm bảo trong Database, field role là 'staff' hoặc tương tự.
  const isStaff = currentUser.role === 'staff' || currentUser.role === 'admin';
  if (!isStaff) {
     return <div style={{ padding: 20 }}>Bạn không có quyền truy cập trang này. <Link to="/">Về trang chủ</Link></div>;
  }

  return (
    <div className="staff-layout-container">
      {/* Sidebar hoặc Header cho Staff */}
      <header style={{ background: '#f0f2f5', padding: '10px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div className="logo">BeAble Staff</div>
        <div className="user-info">
          <span>Xin chào, {currentUser.displayName || currentUser.email}</span>
          <button 
            onClick={() => logout()} 
            style={{ marginLeft: '15px', padding: '5px 10px', cursor: 'pointer' }}
          >
            Đăng xuất
          </button>
        </div>
      </header>
      
      {/* Nội dung chính thay đổi theo route con */}
      <main style={{ padding: '20px' }}>
        <Outlet />
      </main>
    </div>
  );
};

export default StaffLayout;
